import math
import strings

fn main() {
  let a: int = 10
  let b: int = 20
  let sum: int = math.add(a, b)
  let label: string = strings.format("Sum: {}", sum)
  print(label)
}

fn add(a: int, b: int) -> int {
  return a + b
}

fn subtract(a: int, b: int) -> int {
  return a - b
}

